const ie={className:"ReplaceColorBlock",emit(e,t,r,o,c){const l=c.resolve(e,"value",r,o);if("f32"===l.type||"mat4f"===l.type||"texture2d"===l.type||"textureCube"===l.type)throw Error("NodeMaterial:ReplaceColorBlock requires a vector/color value;got "+l.type);const a=c.cast(c.resolve(e,"reference",r,o),l.type).expr,s=c.cast(c.resolve(e,"distance",r,o),"f32").expr,n=c.cast(c.resolve(e,"replacement",r,o),l.type).expr;return{expr:`select(${l.expr},${n},length(${l.expr}-${a})<${s})`,type:l.type};}};export{ie as emitter};